      "params": [
        {
          "name": "searchstring",
          "type": "string",
          "required": true,
          "description": "Natural language search query, e.g., '属于杭州的deepseek概念公司'"
        }
      ],
      "provider_description": "同花顺 (THS) iFinD data provider, offering financial data for Chinese and international markets including stocks, securities, funds, bonds, futures, etc. Supports company announcements, intelligent stock screening, industry analysis, market trend prediction, and more, helping users conduct comprehensive financial data analysis and investment decisions.",
      "stats": {
        "avg_execution_time_ms": 988.17,
        "success_rate": 0.812
      }
    },
    {
      "tool_id": "ths_ifind.hk_connect_stats.v1",
      "name": "iFinD 沪深港通交易统计 (HK Stock Connect Trading Stats)",
      "description": "Query Shanghai-Shenzhen-Hong Kong Stock Connect trading statistics from 同花顺 (THS) iFinD database. Covers northbound (沪股通, 深股通) and southbound (港股通沪市, 港股通深市) channels. Returns trading volume, buy/sell amounts, net buy amount, transaction counts, and top-10 active stocks concentration ratios. Supports daily, weekly, monthly, and yearly aggregation. Useful for tracking cross-border capital flows between mainland China and Hong Kong markets.",
      "params": [
        {
          "name": "sdate",
          "type": "string",
          "required": true,
          "description": "Start date. Supported formats: 'YYYY-MM-DD', 'YYYY/MM/DD', 'YYYYMMDD'."
        },
        {
          "name": "edate",
          "type": "string",
          "required": true,
          "description": "End date. Supported formats: 'YYYY-MM-DD', 'YYYY/MM/DD', 'YYYYMMDD'."
        },
        {
          "name": "zq",
          "type": "string",
          "required": false,
          "description": "Aggregation period. Valid values: 'day', 'week', 'month', 'year'. Defaults to 'week'."
        },
        {
          "name": "lx",
          "type": "string",
          "required": false,
          "description": "Channel type filter. 'ALL'=all channels, '1'=沪股通, '2'=港股通(沪市), '3'=深股通, '4'=港股通(深市). Defaults to 'ALL'."
        },
        {
          "name": "bz",
          "type": "string",
          "required": false,
          "description": "Currency for amounts. Defaults to 'CNY'."
        }
      ],
      "provider_description": "同花顺 (THS) iFinD data provider, offering financial data for Chinese and international markets including stocks, securities, funds, bonds, futures, etc. Supports company announcements, intelligent stock screening, industry analysis, market trend prediction, and more, helping users conduct comprehensive financial data analysis and investment decisions.",
      "stats": {
        "avg_execution_time_ms": 715.71,
        "success_rate": 0.532
      }
    },
    {
      "tool_id": "ths_ifind.real_time_quotation.v1",
      "name": "iFinD 同花顺实时行情 (THS Real-time Quotation)",
      "description": "Query real-time quotation data for securities in the 同花顺 (THS) iFinD database, providing real-time market data for financial products including stocks, funds, bonds, and futures, such as real-time prices, trading volumes, price changes, bid/ask quotes, etc. Supports querying various real-time indicators including latest price, price change, trading volume, turnover ratio, market value, and five-level bid/ask quotes.",
      "params": [
        {
          "name": "codes",
          "type": "string",
          "required": true,
          "description": "Security codes, multiple codes separated by commas (max 50), e.g., '300033.SZ,600030.SH'"
        },
        {
          "name": "indicators",
          "type": "string",
          "required": false,
          "description": "Indicator list, multiple indicators separated by commas. Options: 'common' (common indicators), 'all' (all indicators), or custom indicator list. Default is 'all'"
        }
      ],
      "examples": {
        "sample_parameters": {
          "codes": "300033.SZ,600030.SH"
        }
      },
      "provider_description": "同花顺 (THS) iFinD data provider, offering financial data for Chinese and international markets including stocks, securities, funds, bonds, futures, etc. Supports company announcements, intelligent stock screening, industry analysis, market trend prediction, and more, helping users conduct comprehensive financial data analysis and investment decisions.",
      "stats": {
        "avg_execution_time_ms": 1667.64,
        "success_rate": 0.887
      }
    },
    {
      "tool_id": "ths_ifind.code_converter.v1",
      "name": "iFinD 同花顺证券代码转换 (THS Security Code Converter)",
      "description": "Convert security codes or security names to 同花顺 (THS) standard code format. Supports querying by security code or security name, can specify security type and market, supports exact match or fuzzy match. Returns converted THS codes and related security information.",
      "params": [
        {
          "name": "seccode",
          "type": "string",
          "required": false,
          "description": "Security code, e.g., '000001'. Either seccode or secname"
        },
        {
          "name": "secname",
          "type": "string",
          "required": false,
          "description": "Security name, e.g., '平安银行'. Either seccode or secname"
        },
        {
          "name": "mode",
          "type": "string",
          "required": true,
          "description": "Query mode: 'seccode' (query by code) or 'secname' (query by name)"
        },
        {
          "name": "sectype",
          "type": "string",
          "required": false,
          "description": "Security type, e.g., '001' (stock), default is empty (query all types)"
        },
        {
          "name": "market",
          "type": "string",
          "required": false,
          "description": "Market code, e.g., '212001' (SSE), '212100' (SZSE), default is empty (query all markets)"
        },
        {
          "name": "tradestatus",
          "type": "string",
          "required": false,
          "description": "Trading status: '0' (normal trading), '1' (suspended), '2' (all), default is '0'"
        },
        {
          "name": "isexact",
          "type": "string",
          "required": false,
          "description": "Exact match: '1' (exact match), '0' (fuzzy match), default is '1'"
        }
      ],
      "examples": {
        "sample_parameters": {
          "mode": "seccode",
          "seccode": "000001"
        }
      },
      "provider_description": "同花顺 (THS) iFinD data provider, offering financial data for Chinese and international markets including stocks, securities, funds, bonds, futures, etc. Supports company announcements, intelligent stock screening, industry analysis, market trend prediction, and more, helping users conduct comprehensive financial data analysis and investment decisions.",
      "stats": {
        "avg_execution_time_ms": 582.28,
        "success_rate": 0.98
      }
    },
    {
      "tool_id": "ths_ifind.etf_constituents.v1",
      "name": "iFinD ETF成分股票列表 (ETF Constituent Stock List)",
      "description": "Query the constituent stock list of an ETF from 同花顺 (THS) iFinD database. Returns detailed information about each constituent stock including stock code, name, share quantity, cash substitution flag, subscription/redemption premium ratios and fixed substitution amounts. Useful for analyzing ETF composition and tracking ETF holdings.",
      "params": [
        {
          "name": "thscode",
          "type": "string",
          "required": true,
          "description": "ETF security code, e.g., '510300.SH', '159001.SZ'"
        },
        {
          "name": "date",
          "type": "string",
          "required": false,
          "description": "Query date. Supported formats: 'YYYY-MM-DD', 'YYYY/MM/DD', 'YYYYMMDD'. Defaults to today."
        }
      ],
      "provider_description": "同花顺 (THS) iFinD data provider, offering financial data for Chinese and international markets including stocks, securities, funds, bonds, futures, etc. Supports company announcements, intelligent stock screening, industry analysis, market trend prediction, and more, helping users conduct comprehensive financial data analysis and investment decisions.",
      "stats": {
        "avg_execution_time_ms": 644.44,
        "success_rate": 0.91
      }
    },
    {
      "tool_id": "ths_ifind.report_query.v1",
      "name": "iFinD 同花顺证券公告查询 (THS Security Announcement Query)",
      "description": "Query security announcements in the 同花顺 (THS) iFinD database, supporting filtering and searching by security code, date range, and keywords. Users can input security codes (e.g., '920000.BJ'), announcement keywords (e.g., 'annual report'), and date ranges (e.g., '2024-10-25' to '2025-10-25') to quickly obtain detailed information about relevant announcements, including announcement date, security code, security name, release time, announcement title, announcement link, and unique identifier.",
      "params": [
        {
          "name": "codes",
          "type": "string",
          "required": true,
          "description": "Security code, multiple codes separated by commas (max 50), e.g., '920000.BJ'"
        },
        {
          "name": "keyword",
          "type": "string",
          "required": false,
          "description": "Announcement keyword for searching announcement titles, default is empty string"
        },
        {
          "name": "beginrDate",
          "type": "string",
          "required": true,
          "description": "Start date, format: 'YYYY-MM-DD'"
        },
        {
          "name": "endrDate",
          "type": "string",
          "required": true,
          "description": "End date, format: 'YYYY-MM-DD'"
        }
      ],
      "examples": {
        "sample_parameters": {
          "codes": "920000.BJ",
          "endrDate": "2025-10-25",
          "beginrDate": "2024-10-25"
        }
      },
      "provider_description": "同花顺 (THS) iFinD data provider, offering financial data for Chinese and international markets including stocks, securities, funds, bonds, futures, etc. Supports company announcements, intelligent stock screening, industry analysis, market trend prediction, and more, helping users conduct comprehensive financial data analysis and investment decisions.",
      "stats": {
        "avg_execution_time_ms": 812.59,
        "success_rate": 0.441
      }
    },
    {
      "tool_id": "ths_ifind.company_basics.v1",
      "name": "iFinD 公司基础信息 (Company Basics)",
      "description": "Retrieve the latest (or a specific date) company basics indicators from THS iFinD. Includes company name, industry, comparable/peer companies, concept tags, codes, established date, registration info, main business, and major products.",
      "params": [
        {
          "name": "codes",
          "type": "string",
          "required": true,
          "description": "Security codes, comma-separated (max 50), e.g., '300033.SZ,600030.SH'"
        },
        {
          "name": "date",
          "type": "string",
          "required": false,
          "description": "Date, format: 'YYYYMMDD'. Use this field to query historical values. Defaults to latest."
