      "provider_description": "同花顺 (THS) iFinD data provider, offering financial data for Chinese and international markets including stocks, securities, funds, bonds, futures, etc. Supports company announcements, intelligent stock screening, industry analysis, market trend prediction, and more, helping users conduct comprehensive financial data analysis and investment decisions.",
      "stats": {
        "avg_execution_time_ms": 780.08,
        "success_rate": 0.914
      }
    },
    {
      "tool_id": "ths_ifind.financial_statements.v1",
      "name": "iFinD 同花顺财报 Financial Statements (Balance/Income/Cash Flow)",
      "description": "Query balance sheet, income statement, or cash flow statement data for securities from THS iFinD Financial Statement database using a single entry point.",
      "params": [
        {
          "name": "statement_type",
          "type": "string",
          "required": true,
          "description": "Which statement to query: 'balance', 'income', or 'cash_flow'"
        },
        {
          "name": "codes",
          "type": "string",
          "required": true,
          "description": "Security codes, multiple codes separated by commas (max 50), e.g., '300033.SZ,600030.SH'"
        },
        {
          "name": "year",
          "type": "string",
          "required": true,
          "description": "Year, e.g., '2024'"
        },
        {
          "name": "period",
          "type": "string",
          "required": true,
          "description": "Reporting period: '0331' (Q1), '0630' (H1), '0930' (Q3), '1231' (Annual)"
        },
        {
          "name": "type",
          "type": "string",
          "required": true,
          "description": "Report type: '1' (Consolidated), '2' (Parent Company), '3' (Consolidated Adjusted), '4' (Parent Company Adjusted)"
        }
      ],
      "provider_description": "同花顺 (THS) iFinD data provider, offering financial data for Chinese and international markets including stocks, securities, funds, bonds, futures, etc. Supports company announcements, intelligent stock screening, industry analysis, market trend prediction, and more, helping users conduct comprehensive financial data analysis and investment decisions.",
      "stats": {
        "avg_execution_time_ms": 654.98,
        "success_rate": 0.877
      }
    },
